class Solution:
    def furthestDistanceFromOrigin(self, moves: str) -> int:
        positions = {0}
        for ch in moves:
            nxt = set()
            for p in positions:
                if ch == 'L':
                    nxt.add(p - 1)
                elif ch == 'R':
                    nxt.add(p + 1)
                else:
                    nxt.add(p - 1)
                    nxt.add(p + 1)
            positions = nxt
        return max(abs(p) for p in positions)

