var furthestDistanceFromOrigin = function(moves) {
    let r = 0, l = 0, u = 0;
    for (const ch of moves) {
        if (ch === 'R') r += 1;
        else if (ch === 'L') l += 1;
        else u += 1;
    }
    return Math.abs(r - l) + u;
};
